INSERT INTO english_questions (path_id, topic_id, level, question, options, correct_answer, explanation, difficulty) VALUES

-- ============================================================================
-- SUBTOPIC 1: was/were + V-ing (basic structure) - 20 questions
-- ============================================================================

-- EASY (8 questions)
('foundation', 'past-continuous', 'beginner', 'I _____ working at 5 PM.', '["am", "is", "was", "were"]', 2, 'Past continuous: was/were + V-ing. I + was + working. Past tense of "am" = "was". Shows ongoing past action.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'She _____ reading a book.', '["am", "is", "was", "were"]', 2, 'Past continuous: was/were + V-ing. She + was + reading. Use "was" with he/she/it. Ongoing action in past.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'They _____ playing cricket.', '["am", "is", "was", "were"]', 3, 'Past continuous: was/were + V-ing. They + were + playing. Use "were" with they/we/you. Ongoing past action.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'He _____ watching TV.', '["am", "is", "was", "were"]', 2, 'Past continuous: was/were + V-ing. He + was + watching. Use "was" with he. Shows action in progress in past.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'We _____ studying English.', '["am", "is", "was", "were"]', 3, 'Past continuous: was/were + V-ing. We + were + studying. Use "were" with we. Ongoing action in past.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'You _____ talking to her.', '["am", "is", "was", "were"]', 3, 'Past continuous: was/were + V-ing. You + were + talking. Always "were" with you (singular or plural). Past ongoing.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'It _____ raining yesterday.', '["am", "is", "was", "were"]', 2, 'Past continuous: was/were + V-ing. It + was + raining. Use "was" with it. Weather action in progress.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'The students _____ writing.', '["am", "is", "was", "were"]', 3, 'Past continuous: was/were + V-ing. Students (plural) + were + writing. Plural = "were". Ongoing past action.', 'easy'),

-- MEDIUM (8 questions)
('foundation', 'past-continuous', 'beginner', 'What is wrong? "I were studying."', '["Use was instead of were", "Use am instead of were", "Use is instead of were", "Nothing wrong"]', 0, 'Subject-verb agreement: I + was (not "were"). Correct: "I was studying." I/he/she/it = was, you/we/they = were.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Choose the correct sentence:', '["She was cook dinner.", "She was cooked dinner.", "She was cooking dinner.", "She were cooking dinner."]', 2, 'Past continuous: was + V-ing. Correct: "She was cooking dinner." Must use -ing form (not base or past).', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Arrange correctly: watching / was / He / TV', '["He was watching TV", "He watching was TV", "Was he watching TV", "He was TV watching"]', 0, 'Pattern: Subject + was/were + V-ing + object. Order: He was watching TV. Statement (not question).', 'medium'),

('foundation', 'past-continuous', 'beginner', 'What is the error? "They was playing cricket."', '["Use were instead of was", "Use is instead of was", "Use am instead of was", "Nothing wrong"]', 0, 'Subject-verb agreement: They + were (not "was"). Correct: "They were playing cricket." Plural = "were".', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Talking about what you were doing at 5 PM:', '["I work at 5 PM.", "I worked at 5 PM.", "I was working at 5 PM.", "I am working at 5 PM."]', 2, 'Past continuous: was/were + V-ing. Correct: "I was working at 5 PM." Shows action in progress at specific past time.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Rearrange: studying / We / English / were', '["We were studying English", "We studying were English", "Were we studying English", "We were English studying"]', 0, 'Pattern: Subject + were + V-ing + object. Order: We were studying English. Statement form.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Choose the natural sentence:', '["He was eat lunch.", "He was eating lunch.", "He were eating lunch.", "He is eating lunch."]', 1, 'Past continuous: was + V-ing. Correct: "He was eating lunch." Must use -ing form. Was (not were) with he.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'What is wrong? "She was talked to me."', '["Use talking instead of talked", "Use talk instead of talked", "Use talks instead of talked", "Nothing wrong"]', 0, 'Past continuous: was + V-ing (not past form). Correct: "She was talking to me." Use -ing (not -ed) after was/were.', 'medium'),

-- HARD (4 questions)
('foundation', 'past-continuous', 'beginner', 'Which is correct in formal writing?', '["At 3 PM, we hold a meeting.", "At 3 PM, we held a meeting.", "At 3 PM, we were holding a meeting.", "At 3 PM, we are holding a meeting."]', 2, 'Past continuous: were + V-ing for action in progress at specific past time. "We were holding a meeting at 3 PM" = meeting was ongoing at that time.', 'hard'),

('foundation', 'past-continuous', 'beginner', 'Find the error: "The team were discussing the project."', '["Use was instead of were", "Use is instead of were", "Use am instead of were", "No error"]', 0, 'Collective noun: "team" = singular = was. Correct: "The team was discussing the project." One team = singular.', 'hard'),

('foundation', 'past-continuous', 'beginner', 'Arrange correctly: raining / yesterday / It / was / all / day', '["It was raining all day yesterday", "It was raining yesterday all day", "Yesterday it was raining all day", "It raining was all day yesterday"]', 0, 'Pattern: Subject + was/were + V-ing + duration + time. Natural: It was raining all day yesterday. Duration shows continuous action.', 'hard'),

('foundation', 'past-continuous', 'beginner', 'What is wrong? "Each student were taking the exam."', '["Use was instead of were", "Use is instead of were", "Use am instead of were", "Nothing wrong"]', 0, 'Singular subject: "Each student" = singular = was. Correct: "Each student was taking the exam." "Each" = singular.', 'hard'),

-- ============================================================================
-- SUBTOPIC 2: Interrupted Actions: when + past simple - 20 questions
-- ============================================================================

-- EASY (8 questions)
('foundation', 'past-continuous', 'beginner', 'I was studying _____ the phone rang.', '["when", "while", "during", "if"]', 0, 'Interrupted action: when + past simple interrupts past continuous. Pattern: was V-ing + when + past simple. "When" = interruption point.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'She was cooking _____ I arrived.', '["when", "while", "during", "if"]', 0, 'Interrupted action: when + past simple. Pattern: was V-ing + when + past simple. Arrival interrupted cooking.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'They were playing cricket _____ it started raining.', '["when", "while", "during", "if"]', 0, 'Interrupted action: when + past simple. Pattern: were V-ing + when + past simple. Rain interrupted playing.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'He was sleeping _____ the alarm rang.', '["when", "while", "during", "if"]', 0, 'Interrupted action: when + past simple. Pattern: was V-ing + when + past simple. Alarm interrupted sleeping.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'We were watching TV _____ the power went out.', '["when", "while", "during", "if"]', 0, 'Interrupted action: when + past simple. Pattern: were V-ing + when + past simple. Power cut interrupted watching.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'I was working _____ my boss called.', '["when", "while", "during", "if"]', 0, 'Interrupted action: when + past simple. Pattern: was V-ing + when + past simple. Call interrupted working.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'She was reading _____ I entered.', '["when", "while", "during", "if"]', 0, 'Interrupted action: when + past simple. Pattern: was V-ing + when + past simple. Entering interrupted reading.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'They were eating _____ the doorbell rang.', '["when", "while", "during", "if"]', 0, 'Interrupted action: when + past simple. Pattern: were V-ing + when + past simple. Doorbell interrupted eating.', 'easy'),

-- MEDIUM (8 questions)
('foundation', 'past-continuous', 'beginner', 'What is wrong? "I was study when the phone rang."', '["Use studying instead of study", "Use studied instead of study", "Use studies instead of study", "Nothing wrong"]', 0, 'Past continuous: was + V-ing (not base form). Correct: "I was studying when the phone rang." Must use -ing after was.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Choose the correct sentence:', '["She was cooking when I arrive.", "She was cooking when I arrived.", "She cooked when I was arriving.", "She cooks when I arrived."]', 1, 'Interrupted action: past continuous + when + past simple. Correct: "She was cooking when I arrived." Arrival = interruption.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Arrange correctly: when / was / I / working / boss / my / called', '["I was working when my boss called", "I was working my boss when called", "When my boss called I was working", "I was when working my boss called"]', 0, 'Pattern: Subject + was V-ing + when + subject + past simple. Natural: I was working when my boss called. Interrupted action.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'What is the error? "They was playing when it rained."', '["Use were instead of was", "Use is instead of was", "Use am instead of was", "Nothing wrong"]', 0, 'Subject-verb agreement: They + were (not "was"). Correct: "They were playing when it rained." Plural = "were".', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Describing an interruption:', '["I study when the phone rang.", "I studied when the phone rang.", "I was studying when the phone rang.", "I am studying when the phone rang."]', 2, 'Interrupted action: past continuous + when + past simple. Correct: "I was studying when the phone rang." Ongoing action interrupted.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Rearrange: sleeping / when / was / rang / He / alarm / the', '["He was sleeping when the alarm rang", "He was sleeping the alarm when rang", "When the alarm rang he was sleeping", "He sleeping was when the alarm rang"]', 0, 'Pattern: Subject + was V-ing + when + subject + past simple. Natural: He was sleeping when the alarm rang. Both orders work.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Choose the natural sentence:', '["She was read when I entered.", "She was reading when I entered.", "She reading was when I entered.", "She reads when I entered."]', 1, 'Interrupted action: was + V-ing + when + past simple. Correct: "She was reading when I entered." Must use -ing form.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'What is wrong? "We were watching TV when the power goes out."', '["Use went instead of goes", "Use go instead of goes", "Use going instead of goes", "Nothing wrong"]', 0, 'Tense mismatch: "when" clause needs past simple. Correct: "We were watching TV when the power went out." Goes = present.', 'medium'),

-- HARD (4 questions)
('foundation', 'past-continuous', 'beginner', 'Which is correct storytelling?', '["I walked home when it was raining.", "I was walking home when it started raining.", "I walk home when it rains.", "I am walking home when it rained."]', 1, 'Interrupted action: past continuous + when + past simple. Correct: "I was walking home when it started raining." Ongoing action interrupted by rain starting.', 'hard'),

('foundation', 'past-continuous', 'beginner', 'Find the error: "The team was discussing when the manager came."', '["No error - this is correct", "Use were instead of was", "Use discussed instead of discussing", "Use discuss instead of discussing"]', 0, 'Actually correct! "Team" = collective singular = was. Pattern: was V-ing + when + past simple. No error.', 'hard'),

('foundation', 'past-continuous', 'beginner', 'Arrange correctly: arrived / eating / when / were / I / They', '["They were eating when I arrived", "They were eating I when arrived", "When I arrived they were eating", "They eating were when I arrived"]', 0, 'Pattern: Subject + were V-ing + when + subject + past simple. Natural: They were eating when I arrived. Both orders work.', 'hard'),

('foundation', 'past-continuous', 'beginner', 'What is wrong? "He was work when the fire alarm sounded."', '["Use working instead of work", "Use worked instead of work", "Use works instead of work", "Nothing wrong"]', 0, 'Past continuous: was + V-ing (not base). Correct: "He was working when the fire alarm sounded." Must use -ing after was.', 'hard'),

-- ============================================================================
-- SUBTOPIC 3: Parallel Actions: while + past continuous - 20 questions
-- ============================================================================

-- EASY (8 questions)
('foundation', 'past-continuous', 'beginner', 'I was studying _____ she was cooking.', '["when", "while", "during", "if"]', 1, 'Parallel actions: while + past continuous. Both actions happening at same time. Pattern: was V-ing + while + was V-ing.', 'easy'),

('foundation', 'past-continuous', 'beginner', '_____ I was working, he was sleeping.', '["When", "While", "During", "If"]', 1, 'Parallel actions: while + past continuous. Both actions simultaneous. Pattern: While + was V-ing, was V-ing.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'She was reading _____ I was watching TV.', '["when", "while", "during", "if"]', 1, 'Parallel actions: while + past continuous. Two ongoing actions at same time. Pattern: was V-ing + while + was V-ing.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'They were playing _____ we were studying.', '["when", "while", "during", "if"]', 1, 'Parallel actions: while + past continuous. Simultaneous actions. Pattern: were V-ing + while + were V-ing.', 'easy'),

('foundation', 'past-continuous', 'beginner', '_____ he was cooking, I was cleaning.', '["When", "While", "During", "If"]', 1, 'Parallel actions: while + past continuous. Both happening together. Pattern: While + was V-ing, was V-ing.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'I was working _____ you were sleeping.', '["when", "while", "during", "if"]', 1, 'Parallel actions: while + past continuous. Two simultaneous past actions. Pattern: was V-ing + while + were V-ing.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'She was talking _____ I was listening.', '["when", "while", "during", "if"]', 1, 'Parallel actions: while + past continuous. Both actions at same time. Pattern: was V-ing + while + was V-ing.', 'easy'),

('foundation', 'past-continuous', 'beginner', '_____ they were eating, we were waiting.', '["When", "While", "During", "If"]', 1, 'Parallel actions: while + past continuous. Simultaneous ongoing actions. Pattern: While + were V-ing, were V-ing.', 'easy'),

-- MEDIUM (8 questions)
('foundation', 'past-continuous', 'beginner', 'What is wrong? "I was studying while she cooked."', '["Use was cooking instead of cooked", "Use cooks instead of cooked", "Use cooking instead of cooked", "Nothing wrong"]', 0, 'Parallel actions: both should be past continuous. Correct: "I was studying while she was cooking." While = both ongoing.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Choose the correct sentence:', '["While I worked, he was sleeping.", "While I was working, he was sleeping.", "While I work, he was sleeping.", "While I working, he was sleeping."]', 1, 'Parallel actions: while + past continuous (both sides). Correct: "While I was working, he was sleeping." Both ongoing.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Arrange correctly: while / was / reading / She / was / I / watching / TV', '["She was reading while I was watching TV", "She reading was while I was watching TV", "While I was watching TV she was reading", "She was while reading I was watching TV"]', 0, 'Pattern: Subject + was V-ing + while + subject + was V-ing. Natural: She was reading while I was watching TV. Both orders work.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'What is the error? "While they was playing, we studied."', '["Use were instead of was AND use were studying instead of studied", "Use were instead of was", "Use were studying instead of studied", "Nothing wrong"]', 0, 'Two errors: They = were (not was). Parallel = both continuous. Correct: "While they were playing, we were studying."', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Describing two simultaneous actions:', '["While I cook, he cleaned.", "While I was cooking, he was cleaning.", "While I cooked, he was cleaning.", "While I cooking, he cleaning."]', 1, 'Parallel actions: while + past continuous (both). Correct: "While I was cooking, he was cleaning." Both ongoing at same time.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Rearrange: sleeping / working / was / While / was / I / he', '["While I was working, he was sleeping", "While I working was, he was sleeping", "I was working while he sleeping was", "While was I working, he was sleeping"]', 0, 'Pattern: While + subject + was V-ing, subject + was V-ing. Natural: While I was working, he was sleeping. Parallel ongoing actions.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Choose the natural sentence:', '["While she was talk, I was listen.", "While she was talking, I was listening.", "While she talking was, I listening was.", "While she talks, I was listening."]', 1, 'Parallel actions: while + past continuous (both). Correct: "While she was talking, I was listening." Both -ing forms.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'What is wrong? "He was cooking while I clean."', '["Use was cleaning instead of clean", "Use cleaned instead of clean", "Use cleans instead of clean", "Nothing wrong"]', 0, 'Parallel actions: both should be past continuous. Correct: "He was cooking while I was cleaning." While = both ongoing.', 'medium'),

-- HARD (4 questions)
('foundation', 'past-continuous', 'beginner', 'Which correctly shows simultaneous actions?', '["While the teacher talked, students listen.", "While the teacher was talking, students were listening.", "While the teacher talks, students listened.", "While the teacher was talking, students listen."]', 1, 'Parallel actions: while + past continuous (both). Correct: "While the teacher was talking, students were listening." Both ongoing at same time.', 'hard'),

('foundation', 'past-continuous', 'beginner', 'Find the subtle difference: A) "While I was working, she called." B) "While I was working, she was calling."', '["A = she interrupted, B = both ongoing", "A = both ongoing, B = she interrupted", "Both mean the same", "Both are wrong"]', 0, 'A = interrupted action (call = interruption). B = parallel actions (both ongoing). "Called" = moment, "was calling" = duration.', 'hard'),

('foundation', 'past-continuous', 'beginner', 'Arrange correctly: eating / waiting / While / were / they / were / we', '["While they were eating, we were waiting", "While they were eating we waiting were", "They were eating while we were waiting", "While were they eating, we were waiting"]', 0, 'Pattern: While + subject + were V-ing, subject + were V-ing. Natural: While they were eating, we were waiting. Parallel ongoing.', 'hard'),

('foundation', 'past-continuous', 'beginner', 'What is wrong? "While the team was discussing, the manager enters."', '["Use entered instead of enters", "Use was entering instead of enters", "Use enter instead of enters", "Nothing wrong"]', 1, 'If parallel = both continuous. If interruption = past simple. Correct (parallel): "was entering". Correct (interruption): "entered". "Enters" = present (wrong).', 'hard'),

