-- SUBTOPIC 4: Negative & Questions - 20 questions
-- ============================================================================

-- EASY (8 questions)
('foundation', 'past-continuous', 'beginner', 'I _____ not working yesterday.', '["am", "is", "was", "were"]', 2, 'Past continuous negative: was/were + not + V-ing. I + was + not + working. Pattern: was not working.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'She _____ not reading.', '["am", "is", "was", "were"]', 2, 'Past continuous negative: was/were + not + V-ing. She + was + not + reading. Pattern: was not reading.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'They _____ not playing cricket.', '["am", "is", "was", "were"]', 3, 'Past continuous negative: was/were + not + V-ing. They + were + not + playing. Pattern: were not playing.', 'easy'),

('foundation', 'past-continuous', 'beginner', '_____ you working at 5 PM?', '["Am", "Is", "Was", "Were"]', 3, 'Past continuous question: Was/Were + subject + V-ing? You + were + working. Pattern: Were you working?', 'easy'),

('foundation', 'past-continuous', 'beginner', '_____ she cooking dinner?', '["Am", "Is", "Was", "Were"]', 2, 'Past continuous question: Was/Were + subject + V-ing? She + was + cooking. Pattern: Was she cooking?', 'easy'),

('foundation', 'past-continuous', 'beginner', '_____ they watching TV?', '["Am", "Is", "Was", "Were"]', 3, 'Past continuous question: Was/Were + subject + V-ing? They + were + watching. Pattern: Were they watching?', 'easy'),

('foundation', 'past-continuous', 'beginner', 'He _____ not listening.', '["am", "is", "was", "were"]', 2, 'Past continuous negative: was/were + not + V-ing. He + was + not + listening. Pattern: was not listening.', 'easy'),

('foundation', 'past-continuous', 'beginner', '_____ it raining yesterday?', '["Am", "Is", "Was", "Were"]', 2, 'Past continuous question: Was/Were + subject + V-ing? It + was + raining. Pattern: Was it raining?', 'easy'),

-- MEDIUM (8 questions)
('foundation', 'past-continuous', 'beginner', 'What is wrong? "I weren''t working."', '["Use wasn''t instead of weren''t", "Use isn''t instead of weren''t", "Use am not instead of weren''t", "Nothing wrong"]', 0, 'Subject-verb agreement: I + wasn''t (not "weren''t"). Correct: "I wasn''t working." I/he/she/it = wasn''t, you/we/they = weren''t.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Choose the correct sentence:', '["She wasn''t cook dinner.", "She wasn''t cooked dinner.", "She wasn''t cooking dinner.", "She weren''t cooking dinner."]', 2, 'Past continuous negative: wasn''t + V-ing. Correct: "She wasn''t cooking dinner." Must use -ing form after wasn''t.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Arrange correctly: not / They / playing / were / cricket', '["They were not playing cricket", "They not were playing cricket", "Were they not playing cricket", "They were playing not cricket"]', 0, 'Past continuous negative: Subject + were + not + V-ing. Order: They were not playing cricket. Statement form.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'What is the error? "Was you studying?"', '["Use Were instead of Was", "Use Are instead of Was", "Use Am instead of Was", "Nothing wrong"]', 0, 'Subject-verb agreement: You + were (not "was"). Correct: "Were you studying?" Always "were" with you.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Asking someone about their past activity:', '["You were working at 5 PM?", "Were you working at 5 PM?", "Was you working at 5 PM?", "Are you working at 5 PM?"]', 1, 'Past continuous question: Were + subject + V-ing? Correct: "Were you working at 5 PM?" Formal question structure.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Rearrange: she / Was / reading / book / a', '["Was she reading a book", "She was reading a book", "Reading was she a book", "Was reading she a book"]', 0, 'Past continuous question: Was + subject + V-ing + object. Order: Was she reading a book? Question word order.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Choose the natural sentence:', '["He not was sleeping.", "He wasn''t sleeping.", "He weren''t sleeping.", "He isn''t sleeping."]', 1, 'Past continuous negative: wasn''t + V-ing. Correct: "He wasn''t sleeping." Contraction is natural in speech.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'What is wrong? "They wasn''t playing cricket."', '["Use weren''t instead of wasn''t", "Use isn''t instead of wasn''t", "Use am not instead of wasn''t", "Nothing wrong"]', 0, 'Subject-verb agreement: They + weren''t (not "wasn''t"). Correct: "They weren''t playing cricket." Plural = weren''t.', 'medium'),

-- HARD (4 questions)
('foundation', 'past-continuous', 'beginner', 'Which is correct formal negative?', '["We was not attending the meeting.", "We were not attending the meeting.", "We wasn''t attending the meeting.", "We not were attending the meeting."]', 1, 'Past continuous negative: were + not + V-ing. Correct: "We were not attending the meeting." Formal uses "were not" (not contraction).', 'hard'),

('foundation', 'past-continuous', 'beginner', 'Find the error: "The team wasn''t discussing the project."', '["No error - this is correct", "Use weren''t instead of wasn''t", "Use isn''t instead of wasn''t", "Use discussing instead"]', 0, 'Actually correct! "Team" = collective singular = wasn''t. Pattern: wasn''t + V-ing. No error.', 'hard'),

('foundation', 'past-continuous', 'beginner', 'Arrange correctly: at / you / Were / PM / 5 / working', '["Were you working at 5 PM", "You were working at 5 PM", "Were working you at 5 PM", "At 5 PM were you working"]', 0, 'Past continuous question: Were + subject + V-ing + time. Natural: Were you working at 5 PM? Question structure.', 'hard'),

('foundation', 'past-continuous', 'beginner', 'What is wrong? "Each student wasn''t taking the exam seriously."', '["No error - this is correct", "Use weren''t instead of wasn''t", "Use isn''t instead of wasn''t", "Use taking instead"]', 0, 'Actually correct! "Each student" = singular = wasn''t. Pattern: wasn''t + V-ing. No error.', 'hard'),

-- ============================================================================
-- SUBTOPIC 5: Continuous vs Simple Past (when to use each) - 20 questions
-- ============================================================================

-- EASY (8 questions)
('foundation', 'past-continuous', 'beginner', 'Which shows action in progress? A) I worked at 5 PM. B) I was working at 5 PM.', '["A (Simple Past)", "B (Past Continuous)", "Both mean the same", "Neither is correct"]', 1, 'Past continuous = action in progress at specific time. Simple past = completed action. "Was working at 5 PM" = ongoing at that moment.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'I _____ to music all evening. (duration/ongoing)', '["listen", "listened", "was listening", "am listening"]', 2, 'Past continuous for duration: was/were + V-ing. "Was listening all evening" = ongoing activity over period. Shows duration.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'She _____ her homework quickly. (completed action)', '["finish", "finished", "was finishing", "is finishing"]', 1, 'Simple past for completed action: past simple. "Finished" = completed task. No emphasis on duration.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'They _____ at 9 PM yesterday. (action in progress at specific time)', '["study", "studied", "were studying", "are studying"]', 2, 'Past continuous for specific time: were + V-ing. "Were studying at 9 PM" = action in progress at that moment.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'He _____ his keys. (simple completed action)', '["lose", "lost", "was losing", "is losing"]', 1, 'Simple past for completed action: lost. "Lost" = completed event (no duration emphasis). Quick finished action.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'We _____ for hours. (emphasis on duration)', '["wait", "waited", "were waiting", "are waiting"]', 2, 'Past continuous for duration: were + V-ing. "Were waiting for hours" = emphasizes length of time. Duration focus.', 'easy'),

('foundation', 'past-continuous', 'beginner', 'I _____ the movie. (simple completed action)', '["watch", "watched", "was watching", "am watching"]', 1, 'Simple past for completed action: watched. "Watched the movie" = finished watching (no duration emphasis).', 'easy'),

('foundation', 'past-continuous', 'beginner', 'She _____ all day. (emphasis on continuous activity)', '["work", "worked", "was working", "is working"]', 2, 'Past continuous for emphasis: was + V-ing. "Was working all day" = emphasizes continuous nature of activity.', 'easy'),

-- MEDIUM (8 questions)
('foundation', 'past-continuous', 'beginner', 'What''s the difference? A) "It rained." B) "It was raining."', '["A = fact, B = emphasizes duration/atmosphere", "A = emphasizes duration, B = fact", "Both mean the same", "Both are wrong"]', 0, 'Simple past = fact (it rained, then stopped). Past continuous = atmosphere/duration (it was raining = setting the scene). Emphasis difference!', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Choose the correct sentence for storytelling:', '["The sun shone, birds sang.", "The sun was shining, birds were singing.", "The sun shine, birds sing.", "The sun is shining, birds are singing."]', 1, 'Past continuous for scene-setting: was/were + V-ing. "Was shining, were singing" = creates atmosphere in story. Background actions.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Complete: I _____ when you called. (action in progress - interrupted)', '["study", "studied", "was studying", "am studying"]', 2, 'Past continuous for interrupted action: was + V-ing. "Was studying when you called" = ongoing action interrupted. Continuous = background.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'What is wrong using? "I was arriving at 5 PM."', '["Use arrived instead - arrival is a moment, not duration", "Use arrive instead", "Use am arriving instead", "Nothing wrong"]', 0, 'Arrival = moment (not duration). Use simple past. Correct: "I arrived at 5 PM." Momentary actions don''t use continuous.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Describing what you saw:', '["When I entered, she worked at her desk.", "When I entered, she was working at her desk.", "When I entered, she works at her desk.", "When I enter, she was working at her desk."]', 1, 'Past continuous for scene description: was + V-ing. "She was working at her desk" = describes the scene I saw. Background activity.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Choose the better storytelling:', '["The phone rang. I answered it.", "The phone was ringing. I was answering it.", "The phone ringing. I answering it.", "The phone rings. I answer it."]', 0, 'Simple past for sequence of quick actions: rang, answered. Continuous not needed for quick sequential events. Simple past = story flow.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'Complete: At 8 AM, I _____ breakfast. (action in progress at specific time)', '["eat", "ate", "was eating", "am eating"]', 2, 'Past continuous for specific time: was + V-ing. "Was eating at 8 AM" = action in progress at that moment. Time = continuous.', 'medium'),

('foundation', 'past-continuous', 'beginner', 'What is the error? "I was knowing the answer."', '["Use knew instead - know is stative", "Use know instead", "Use am knowing instead", "Nothing wrong"]', 0, 'Stative verbs don''t use continuous! Know = state (not action). Correct: "I knew the answer." Stative = simple past only.', 'medium'),

-- HARD (4 questions)
('foundation', 'past-continuous', 'beginner', 'Which correctly describes background + main event?', '["It rained when we arrived.", "It was raining when we arrived.", "It rains when we arrived.", "It is raining when we arrived."]', 1, 'Past continuous = background, simple past = main event. "It was raining when we arrived" = rain (background), arrival (main). Scene-setting!', 'hard'),

('foundation', 'past-continuous', 'beginner', 'Find the subtle difference: A) "I lived in Mumbai for 5 years." B) "I was living in Mumbai for 5 years."', '["A = finished period, B = temporary/not settled feeling", "A = temporary, B = finished", "Both mean the same", "Both are wrong"]', 0, 'Simple past = neutral fact (lived there, maybe still do). Past continuous = emphasizes temporary nature or ongoing at that time. Subtle emphasis!', 'hard'),

('foundation', 'past-continuous', 'beginner', 'Choose the natural narrative:', '["The teacher entered. The students stood up.", "The teacher was entering. The students were standing up.", "The teacher enters. The students stand up.", "The teacher entering. The students standing up."]', 0, 'Simple past for sequence of quick actions: entered, stood up. Natural storytelling = simple past. Quick sequential events = simple.', 'hard'),

('foundation', 'past-continuous', 'beginner', 'What is wrong? "I was understanding the lesson."', '["Use understood instead - understand is stative", "Use understand instead", "Use am understanding instead", "Nothing wrong"]', 0, 'Stative verbs don''t use continuous! Understand = mental state (not action). Correct: "I understood the lesson." Stative = no continuous.', 'hard');

